script:
angular.module('GT01', [])
.controller('GT01', ["$scope","$http","$location", function ($scope, $http, $location) {

    $scope.ID = 'GT01';
    $scope.i18n = function(key){
        return Funifier.i18n.get("GT01", key);
    };
    $scope.player = {};
    $scope.challenges = [];

    $scope.load = function(){
        if(Funifier.auth.getAuthorization()) {
            var me = "me";
            if(Funifier.widget.options && Funifier.widget.options[$scope.ID] && Funifier.widget.options[$scope.ID].player) {
                me = Funifier.widget.options[$scope.ID].player;
            }
            var req = {
                method: "GET", url:Funifier.config.service+"/v3/player/" + me + "/status", 
                headers: {"Authorization": Funifier.auth.getAuthorization(), "content-type": "application/json", "cache-control": "no-cache"}
            };
            $http(req).then(function(data){
                if(data.data && data.data._id) {
                    $scope.player = data.data;
                }
            }, function(err){
                console.log(err);
            });
        }
    };
    $scope.load();


    $scope.getChallenge = function(ID){
        var o = {};
        var list = $scope.challenges || [];
        list.forEach(function(el){if(el._id==ID){o = el;}});
        return o;
    };
    $scope.loadChallenges = function(){
        var req = {
            method: "GET", url:Funifier.config.service+"/v3/challenge?fields=challenge,badge", 
            headers: {"Authorization": Funifier.auth.getAuthorization(), "content-type": "application/json", "cache-control": "no-cache"}
        };

        $http(req).then(function(data){
            $scope.challenges = data.data;
        }, function(err){
            console.log(err);
        });
    };

    $scope.loadChallenges();
}]);

setTimeout(function () {
     var element = angular.element(document.getElementById('GT01'));
     if (!element.injector()) {
         angular.bootstrap(element, ['GT01']);
     }
}, 10);

